class Solution {
    public int[] earliestAndLatest(int n, int firstPlayer, int secondPlayer) {
        int earliest = (int) Math.ceil(Math.log(Math.min(firstPlayer - 1, n - secondPlayer + 1)) / Math.log(2)) + 1;
        int latest = (int) Math.ceil(Math.log(n) / Math.log(2));
        return new int[]{earliest, latest};
    }
}
